/**
 * Unit tests for the spawn-depth registry (CC 2.1.172 nested sub-agents).
 *
 * Uses a real temp directory — the module is plain fs I/O with
 * best-effort semantics, so exercising it against disk is both simpler
 * and stricter than mocking node:fs.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, join } from 'node:path';
import {
  resolveAndRecordDepth,
  registryPath,
  MAX_SPAWN_DEPTH,
  SPAWN_DEPTH_BUDGET,
} from '../../lib/spawn-depth.js';

let projectDir: string;

beforeEach(() => {
  projectDir = mkdtempSync(join(tmpdir(), 'spawn-depth-'));
});

afterEach(() => {
  rmSync(projectDir, { recursive: true, force: true });
});

describe('resolveAndRecordDepth', () => {
  it('returns 1 for a main-loop spawn (no parent)', () => {
    expect(resolveAndRecordDepth(projectDir, 'a1', undefined)).toBe(1);
  });

  it('records depth so a child resolves parent + 1', () => {
    resolveAndRecordDepth(projectDir, 'a1', undefined); // depth 1
    expect(resolveAndRecordDepth(projectDir, 'b1', 'a1')).toBe(2);
    expect(resolveAndRecordDepth(projectDir, 'c1', 'b1')).toBe(3);
    expect(resolveAndRecordDepth(projectDir, 'd1', 'c1')).toBe(4);
  });

  it('caps at MAX_SPAWN_DEPTH (CC hard cap of 5)', () => {
    let parent: string | undefined;
    let depth = 0;
    for (let i = 0; i < 7; i++) {
      const id = `agent-${i}`;
      depth = resolveAndRecordDepth(projectDir, id, parent);
      parent = id;
    }
    expect(depth).toBe(MAX_SPAWN_DEPTH);
  });

  it('falls back to depth 2 when parent is unknown', () => {
    expect(resolveAndRecordDepth(projectDir, 'orphan', 'never-seen')).toBe(2);
  });

  it('returns a usable depth without recording when agent_id is missing', () => {
    resolveAndRecordDepth(projectDir, 'a1', undefined);
    expect(resolveAndRecordDepth(projectDir, undefined, 'a1')).toBe(2);
    // Nothing new persisted for the undefined id.
    const raw = JSON.parse(readFileSync(registryPath(projectDir), 'utf8'));
    expect(Object.keys(raw)).toEqual(['a1']);
  });

  it('survives a corrupt registry file (best-effort reset)', () => {
    const path = registryPath(projectDir);
    mkdirSync(dirname(path), { recursive: true });
    writeFileSync(path, 'not-json{{{');
    expect(resolveAndRecordDepth(projectDir, 'a1', undefined)).toBe(1);
    expect(resolveAndRecordDepth(projectDir, 'b1', 'a1')).toBe(2);
  });

  it('ignores non-integer registry values', () => {
    const path = registryPath(projectDir);
    mkdirSync(dirname(path), { recursive: true });
    writeFileSync(path, JSON.stringify({ a1: 'three', a2: 2.5, a3: -1 }));
    // All invalid → parents unknown → fallback depth 2.
    expect(resolveAndRecordDepth(projectDir, 'b1', 'a1')).toBe(2);
  });

  it('prunes the registry once it exceeds the cap', () => {
    for (let i = 0; i < 450; i++) {
      resolveAndRecordDepth(projectDir, `agent-${i}`, undefined);
    }
    const raw = JSON.parse(readFileSync(registryPath(projectDir), 'utf8'));
    const keys = Object.keys(raw);
    expect(keys.length).toBeLessThanOrEqual(401);
    // Newest entries survive pruning.
    expect(keys).toContain('agent-449');
    expect(keys).not.toContain('agent-0');
  });

  it('exports a budget below the hard cap', () => {
    expect(SPAWN_DEPTH_BUDGET).toBeLessThan(MAX_SPAWN_DEPTH);
  });
});
